            barrier(CLK_LOCAL_MEM_FENCE);

            count = WIN_SY * VERTICAL_STRIDE - 1;
            centerOffset = 7 * VERTICAL_STRIDE;
            prevOffset = ODD_OFFSET;
            nextOffset = prevOffset + 1;

            offset = 7 * VERTICAL_STRIDE;
            sc_count = WIN_SY * VERTICAL_STRIDE;
            sc_steps = sc_count / WIN_SX;
            sc_finalCount = sc_count % WIN_SX;
            sc_finalOffset = sc_count - sc_finalCount;

            for(int i = 0; i < sc_steps; i++) {
                buffer[local_x + i * WIN_SX + offset] *= scale97Mul;
                buffer[local_x + i * WIN_SX + offset + ODD_OFFSET] *= scale97Div;
            }
            if(local_x < sc_finalCount) {
                buffer[local_x + sc_finalOffset + offset] *= scale97Mul;
                buffer[local_x + sc_finalOffset + offset + ODD_OFFSET] *= scale97Div;
            }
            barrier(CLK_LOCAL_MEM_FENCE);

            STEPS = count / WIN_SX;
            finalCount = count % WIN_SX;
            finalOffset = count - finalCount;

            for(int i = 0; i < STEPS; i++) {
                float previous = buffer[prevOffset + i * WIN_SX + local_x];
                float next = buffer[nextOffset + i * WIN_SX + local_x];
                int center_idx = centerOffset + i * WIN_SX + local_x;
                float center = buffer[center_idx];
                center += r97update2 * (previous + next);
                buffer[center_idx] = center;
            }
            if(local_x < finalCount) {
                float previous = buffer[prevOffset + finalOffset + local_x];
                float next = buffer[nextOffset + finalOffset + local_x];
                int center_idx = centerOffset + finalOffset + local_x;
                float center = buffer[center_idx];
                center += r97update2 * (previous + next);
                buffer[center_idx] = center;
            }
            barrier(CLK_LOCAL_MEM_FENCE);

            centerOffset = ODD_OFFSET;
            prevOffset = 0;
            nextOffset = 1;

            STEPS = count / WIN_SX;
            finalCount = count % WIN_SX;
            finalOffset = count - finalCount;

            for(int i = 0; i < STEPS; i++) {
                float previous = buffer[prevOffset + i * WIN_SX + local_x];
                float next = buffer[nextOffset + i * WIN_SX + local_x];
                int center_idx = centerOffset + i * WIN_SX + local_x;
                float center = buffer[center_idx];
                center += r97predict2 * (previous + next);
                buffer[center_idx] = center;
            }
            if(local_x < finalCount) {
                float previous = buffer[prevOffset + finalOffset + local_x];
                float next = buffer[nextOffset + finalOffset + local_x];
                int center_idx = centerOffset + finalOffset + local_x;
                float center = buffer[center_idx];
                center += r97predict2 * (previous + next);
                buffer[center_idx] = center;
            }
            barrier(CLK_LOCAL_MEM_FENCE);

            centerOffset = 1 * VERTICAL_STRIDE;
            prevOffset = ODD_OFFSET + 1 * VERTICAL_STRIDE;
            nextOffset = prevOffset + 1;

            STEPS = count / WIN_SX;
            finalCount = count % WIN_SX;
            finalOffset = count - finalCount;

            for(int i = 0; i < STEPS; i++) {
                float previous = buffer[prevOffset + i * WIN_SX + local_x];
                float next = buffer[nextOffset + i * WIN_SX + local_x];
                int center_idx = centerOffset + i * WIN_SX + local_x;
                float center = buffer[center_idx];
                center += r97update1 * (previous + next);
                buffer[center_idx] = center;
            }
            if(local_x < finalCount) {
                float previous = buffer[prevOffset + finalOffset + local_x];
                float next = buffer[nextOffset + finalOffset + local_x];
                int center_idx = centerOffset + finalOffset + local_x;
                float center = buffer[center_idx];
                center += r97update1 * (previous + next);
                buffer[center_idx] = center;
            }
            barrier(CLK_LOCAL_MEM_FENCE);

            centerOffset = ODD_OFFSET + 1 * VERTICAL_STRIDE;
            prevOffset = 1 * VERTICAL_STRIDE;
            nextOffset = prevOffset + 1;

            STEPS = count / WIN_SX;
            finalCount = count % WIN_SX;
            finalOffset = count - finalCount;

            for(int i = 0; i < STEPS; i++) {
                float previous = buffer[prevOffset + i * WIN_SX + local_x];
                float next = buffer[nextOffset + i * WIN_SX + local_x];
                int center_idx = centerOffset + i * WIN_SX + local_x;
                float center = buffer[center_idx];
                center += r97Predict1 * (previous + next);
                buffer[center_idx] = center;
            }
            if(local_x < finalCount) {
                float previous = buffer[prevOffset + finalOffset + local_x];
                float next = buffer[nextOffset + finalOffset + local_x];
                int center_idx = centerOffset + finalOffset + local_x;
                float center = buffer[center_idx];
                center += r97Predict1 * (previous + next);
                buffer[center_idx] = center;
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        for(int i = 0; i < 7; i++) {
            last7Lines[i] = buffer[columnOffset + (WIN_SY + i) * VERTICAL_STRIDE];
        }

        for(int i = 0; i < (WIN_SY + 7); i++) {
            if(i & 1) {
                buffer[columnOffset + i * VERTICAL_STRIDE] *= scale97Div;
            } else {
                buffer[columnOffset + i * VERTICAL_STRIDE] *= scale97Mul;
            }
        }

        for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
            int row = i * 2 + 1;
            float prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
            float next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
            int center_idx = columnOffset + row * VERTICAL_STRIDE;
            float center = buffer[center_idx];
            center += r97update2 * (prev + next);
            buffer[center_idx] = center;
        }
        if(WIN_SY > 3) {
            for(int i = 0; i < WIN_SY / 2 - 1; i++) {
                int row = 2 + i * 2;
                float prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
                float next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
                int center_idx = columnOffset + row * VERTICAL_STRIDE;
                float center = buffer[center_idx];
                center += r97predict2 * (prev + next);
                buffer[center_idx] = center;
            }
        }
        for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
            int row = i * 2 + 1;
            float prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
            float next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
            int center_idx = columnOffset + row * VERTICAL_STRIDE;
            float center = buffer[center_idx];
            center += r97update1 * (prev + next);
            buffer[center_idx] = center;
        }
        if(WIN_SY > 3) {
            for(int i = 0; i < WIN_SY / 2 - 1; i++) {
                int row = 2 + i * 2;
                float prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
                float next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
                int center_idx = columnOffset + row * VERTICAL_STRIDE;
                float center = buffer[center_idx];
                center += r97Predict1 * (prev + next);
                buffer[center_idx] = center;
            }
        }

        for(int i = 3; i < (3 + WIN_SY); i++) {
            if(writer_next != writer_end) {
                out[writer_next] = buffer[columnOffset + i * VERTICAL_STRIDE];
                writer_next += strideLowToHigh;
            }
        }

        for(int i = 0; i < 7; i++) {
            buffer[columnOffset + i * VERTICAL_STRIDE] = last7Lines[i];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }
}
